+/**
+ * Webhook notification adapter.
+ *
+ * Implements the NotificationAdapter interface for webhook delivery.
+ * Accepts a URL as the recipient, formats the notification payload as
+ * JSON, and POSTs it to the endpoint.
+ *
+ * ## Features
+ *
+ * - **URL validation**: Validates that the recipient is a well-formed
+ *   HTTP or HTTPS URL before attempting delivery.
+ * - **JSON payload formatting**: Converts NotificationPayload into a
+ *   structured JSON payload with event type, timestamp, subject, body,
+ *   priority, and optional metadata.
+ * - **Priority passthrough**: The notification priority is included
+ *   directly in the webhook payload for downstream consumers.
+ *
+ * ## Usage
+ *
+ * ```typescript
+ * const webhookAdapter = new WebhookAdapter();
+ * notificationService.registerAdapter(webhookAdapter);
+ * ```
+ *
+ * ## Payload format
+ *
+ * The webhook POSTs a JSON body with the following structure:
+ * ```json
+ * {
+ *   "event": "notification",
+ *   "timestamp": "2024-01-01T00:00:00.000Z",
+ *   "subject": "Order Confirmation: ORD-001",
+ *   "body": "Your order has been placed.",
+ *   "priority": "normal",
+ *   "metadata": { ... }
+ * }
+ * ```
+ *
+ * ## Replacing with a real HTTP client
+ *
+ * To use a real HTTP client (fetch, axios, etc.), modify the `send()`
+ * method to POST the formatted payload to the URL. Wrap HTTP errors
+ * and return `{ success: false, error: '...' }`.
+ */
+
+import type { NotificationAdapter } from './notification.adapter.js';
+import type {
+  NotificationPayload,
+  NotificationResult,
+  NotificationType,
+  NotificationPriority,
+} from '../models/notification.js';
+import { Logger } from '../utils/logger.js';
+
+/**
+ * The JSON payload sent to webhook endpoints.
+ */
+export interface WebhookPayload {
+  /** Event type identifier. */
+  event: string;
+
+  /** ISO timestamp of when the webhook was sent. */
+  timestamp: string;
+
+  /** Notification subject. */
+  subject: string;
+
+  /** Notification body content. */
+  body: string;
+
+  /** Priority level. */
+  priority: NotificationPriority;
+
+  /** Optional metadata passed through from the notification payload. */
+  metadata?: Record<string, unknown>;
+}
+
+/**
+ * A webhook delivery record stored by the adapter.
+ * Includes the URL, formatted payload, and simulated response.
+ * Useful for testing and asserting on sent webhooks.
+ */
+export interface SentWebhook {
+  /** Unique message identifier (e.g., `webhook-0001`). */
+  messageId: string;
+
+  /** The URL the webhook was POSTed to. */
+  url: string;
+
+  /** The JSON payload that was sent. */
+  payload: WebhookPayload;
+
+  /** HTTP status code of the response (simulated as 200). */
+  statusCode: number;
+
+  /** When the webhook was sent. */
+  sentAt: Date;
+}
+
+/** URL validation — must start with http:// or https:// and have a host. */
+const URL_REGEX = /^https?:\/\/[^\s/$.?#].[^\s]*$/i;
+
+let nextMessageId = 1;
+
+function generateMessageId(): string {
+  return `webhook-${String(nextMessageId++).padStart(4, '0')}`;
+}
+
+/**
+ * Reset the message ID counter. For testing only.
+ */
+export function resetWebhookMessageIdCounter(): void {
+  nextMessageId = 1;
+}
+
+export class WebhookAdapter implements NotificationAdapter {
+  readonly type: NotificationType = 'webhook';
+  private logger = new Logger('WebhookAdapter');
+  private sentWebhooks: SentWebhook[] = [];
+
+  /**
+   * Validate a webhook URL.
+   *
+   * The URL must be a well-formed HTTP or HTTPS URL. Other schemes
+   * (ftp, ws, etc.) are rejected.
+   *
+   * @param url - The URL string to validate.
+   * @returns true if the URL is valid for webhook delivery.
+   */
+  validateUrl(url: string): boolean {
+    return URL_REGEX.test(url.trim());
+  }
+
+  /**
+   * Format a notification payload into a webhook JSON payload.
+   *
+   * The formatted payload includes:
+   * - `event`: Always `"notification"`
+   * - `timestamp`: ISO 8601 timestamp of when the payload was formatted
+   * - `subject`: The notification subject
+   * - `body`: The notification body
+   * - `priority`: The notification priority (defaults to `"normal"`)
+   * - `metadata`: Optional pass-through metadata from the notification
+   *
+   * @param payload - The notification payload to format.
+   * @returns The structured webhook payload ready for JSON serialization.
+   */
+  formatPayload(payload: NotificationPayload): WebhookPayload {
+    const webhookPayload: WebhookPayload = {
+      event: 'notification',
+      timestamp: new Date().toISOString(),
+      subject: payload.subject,
+      body: payload.body,
+      priority: payload.priority ?? 'normal',
+    };
+
+    if (payload.metadata && Object.keys(payload.metadata).length > 0) {
+      webhookPayload.metadata = { ...payload.metadata };
+    }
+
+    return webhookPayload;
+  }
+
+  /**
+   * Send a notification via webhook POST.
+   *
+   * Validates the recipient URL, formats the payload as JSON, and
+   * records the delivery. Returns a failure result if the URL is
+   * invalid. Never throws.
+   *
+   * @param payload - The notification payload to deliver via webhook.
+   * @returns A result indicating delivery success or failure.
+   */
+  async send(payload: NotificationPayload): Promise<NotificationResult> {
+    const timestamp = new Date();
+
+    try {
+      // 1. Validate URL
+      const url = payload.recipient.trim();
+      if (!this.validateUrl(url)) {
+        this.logger.error(`Invalid webhook URL: ${payload.recipient}`);
+        return {
+          success: false,
+          error: `Invalid webhook URL: ${payload.recipient}`,
+          timestamp,
+        };
+      }
+
+      // 2. Format payload
+      const webhookPayload = this.formatPayload(payload);
+
+      // 3. Generate ID and store sent webhook
+      const messageId = generateMessageId();
+
+      const sentWebhook: SentWebhook = {
+        messageId,
+        url,
+        payload: webhookPayload,
+        statusCode: 200,
+        sentAt: timestamp,
+      };
+
+      this.sentWebhooks.push(sentWebhook);
+      this.logger.info(
+        `Webhook sent: ${messageId} to ${url} — "${payload.subject}"`,
+      );
+
+      return {
+        success: true,
+        messageId,
+        timestamp,
+      };
+    } catch (err) {
+      const errorMessage =
+        err instanceof Error ? err.message : 'Unknown webhook delivery error';
+      this.logger.error(
+        `Webhook delivery failed for ${payload.recipient}: ${errorMessage}`,
+      );
+
+      return {
+        success: false,
+        error: errorMessage,
+        timestamp,
+      };
+    }
+  }
+
+  /**
+   * Get all webhooks sent through this adapter. Useful for testing.
+   */
+  getSentWebhooks(): SentWebhook[] {
+    return [...this.sentWebhooks];
+  }
+
+  /**
+   * Get webhooks sent to a specific URL. Useful for testing.
+   */
+  getSentWebhooksTo(url: string): SentWebhook[] {
+    return this.sentWebhooks.filter((w) => w.url === url);
+  }
+
+  /**
+   * Get the count of sent webhooks.
+   */
+  getSentWebhookCount(): number {
+    return this.sentWebhooks.length;
+  }
+
+  /**
+   * Clear all sent webhooks. Useful for testing.
+   */
+  clearSentWebhooks(): void {
+    this.sentWebhooks = [];
+  }
+}

