import { describe, it, expect, beforeEach } from 'vitest';
import {
  WebhookAdapter,
  resetWebhookMessageIdCounter,
} from '../../src/adapters/webhook.adapter.js';
import type {
  WebhookPayload,
  SentWebhook,
} from '../../src/adapters/webhook.adapter.js';
import type { NotificationPayload } from '../../src/models/notification.js';

describe('WebhookAdapter', () => {
  let adapter: WebhookAdapter;

  beforeEach(() => {
    adapter = new WebhookAdapter();
    resetWebhookMessageIdCounter();
  });

  describe('type', () => {
    it('should have type "webhook"', () => {
      expect(adapter.type).toBe('webhook');
    });
  });

  // ---------------------------------------------------------------------------
  // validateUrl
  // ---------------------------------------------------------------------------
  describe('validateUrl', () => {
    it('should accept a valid HTTPS URL', () => {
      expect(adapter.validateUrl('https://example.com/webhooks')).toBe(true);
    });

    it('should accept a valid HTTP URL', () => {
      expect(adapter.validateUrl('http://example.com/webhooks')).toBe(true);
    });

    it('should accept a URL with port', () => {
      expect(adapter.validateUrl('https://example.com:8080/hook')).toBe(true);
    });

    it('should accept a URL with path and query params', () => {
      expect(adapter.validateUrl('https://example.com/api/webhook?token=abc123')).toBe(true);
    });

    it('should accept a URL with subdomain', () => {
      expect(adapter.validateUrl('https://hooks.slack.com/services/T00/B00/xxx')).toBe(true);
    });

    it('should reject an empty string', () => {
      expect(adapter.validateUrl('')).toBe(false);
    });

    it('should reject a plain string', () => {
      expect(adapter.validateUrl('not-a-url')).toBe(false);
    });

    it('should reject an email address', () => {
      expect(adapter.validateUrl('alice@example.com')).toBe(false);
    });

    it('should reject a URL without scheme', () => {
      expect(adapter.validateUrl('example.com/webhooks')).toBe(false);
    });

    it('should reject ftp scheme', () => {
      expect(adapter.validateUrl('ftp://example.com/file')).toBe(false);
    });

    it('should handle leading/trailing whitespace', () => {
      expect(adapter.validateUrl('  https://example.com/hook  ')).toBe(true);
    });
  });

  // ---------------------------------------------------------------------------
  // formatPayload
  // ---------------------------------------------------------------------------
  describe('formatPayload', () => {
    it('should format a basic notification payload', () => {
      const payload: NotificationPayload = {
        type: 'webhook',
        recipient: 'https://example.com/hook',
        subject: 'Order Confirmation',
        body: 'Your order has been placed.',
        priority: 'normal',
      };

      const result = adapter.formatPayload(payload);

      expect(result.event).toBe('notification');
      expect(result.subject).toBe('Order Confirmation');
      expect(result.body).toBe('Your order has been placed.');
      expect(result.priority).toBe('normal');
      expect(result.timestamp).toBeDefined();
      expect(result.metadata).toBeUndefined();
    });

    it('should include metadata when present', () => {
      const payload: NotificationPayload = {
        type: 'webhook',
        recipient: 'https://example.com/hook',
        subject: 'Test',
        body: 'Body',
        metadata: { orderId: 'ORD-001', userId: 'user-1' },
      };

      const result = adapter.formatPayload(payload);

      expect(result.metadata).toEqual({ orderId: 'ORD-001', userId: 'user-1' });
    });

    it('should not include metadata when it is empty', () => {
      const payload: NotificationPayload = {
        type: 'webhook',
        recipient: 'https://example.com/hook',
        subject: 'Test',
        body: 'Body',
        metadata: {},
      };

      const result = adapter.formatPayload(payload);

      expect(result.metadata).toBeUndefined();
    });

    it('should default priority to normal when not specified', () => {
      const payload: NotificationPayload = {
        type: 'webhook',
        recipient: 'https://example.com/hook',
        subject: 'Test',
        body: 'Body',
      };

      const result = adapter.formatPayload(payload);

      expect(result.priority).toBe('normal');
    });

    it('should preserve urgent priority', () => {
      const payload: NotificationPayload = {
        type: 'webhook',
        recipient: 'https://example.com/hook',
        subject: 'Alert',
        body: 'Critical issue.',
        priority: 'urgent',
      };

      const result = adapter.formatPayload(payload);

      expect(result.priority).toBe('urgent');
    });

    it('should produce a valid ISO timestamp', () => {
      const payload: NotificationPayload = {
        type: 'webhook',
        recipient: 'https://example.com/hook',
        subject: 'Test',
        body: 'Body',
      };

      const result = adapter.formatPayload(payload);

      // Should be a valid ISO 8601 date string
      const parsed = new Date(result.timestamp);
      expect(parsed.toISOString()).toBe(result.timestamp);
    });

    it('should create a copy of metadata, not a reference', () => {
      const metadata = { key: 'value' };
      const payload: NotificationPayload = {
        type: 'webhook',
        recipient: 'https://example.com/hook',
        subject: 'Test',
        body: 'Body',
        metadata,
      };

      const result = adapter.formatPayload(payload);

      expect(result.metadata).toEqual(metadata);
      expect(result.metadata).not.toBe(metadata);
    });
  });

  // ---------------------------------------------------------------------------
  // send
  // ---------------------------------------------------------------------------
  describe('send', () => {
    it('should send a webhook successfully to a valid URL', async () => {
      const result = await adapter.send({
        type: 'webhook',
        recipient: 'https://example.com/webhooks/notifications',
        subject: 'Order Confirmation: ORD-001',
        body: 'Your order has been placed.',
        priority: 'normal',
      });

      expect(result.success).toBe(true);
      expect(result.messageId).toBe('webhook-0001');
      expect(result.timestamp).toBeInstanceOf(Date);
      expect(result.error).toBeUndefined();
    });

    it('should store the sent webhook with all fields', async () => {
      await adapter.send({
        type: 'webhook',
        recipient: 'https://example.com/hook',
        subject: 'Order Confirmation: ORD-001',
        body: 'Items: Widget x2. Total: $20.00',
        priority: 'high',
        metadata: { orderId: 'ORD-001' },
      });

      const webhooks = adapter.getSentWebhooks();
      expect(webhooks).toHaveLength(1);

      const webhook = webhooks[0]!;
      expect(webhook.messageId).toBe('webhook-0001');
      expect(webhook.url).toBe('https://example.com/hook');
      expect(webhook.statusCode).toBe(200);
      expect(webhook.sentAt).toBeInstanceOf(Date);
      expect(webhook.payload.event).toBe('notification');
      expect(webhook.payload.subject).toBe('Order Confirmation: ORD-001');
      expect(webhook.payload.body).toBe('Items: Widget x2. Total: $20.00');
      expect(webhook.payload.priority).toBe('high');
      expect(webhook.payload.metadata).toEqual({ orderId: 'ORD-001' });
    });

    it('should fail for an invalid URL', async () => {
      const result = await adapter.send({
        type: 'webhook',
        recipient: 'not-a-valid-url',
        subject: 'Test',
        body: 'Test body',
      });

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid webhook URL');
      expect(result.error).toContain('not-a-valid-url');
      expect(adapter.getSentWebhookCount()).toBe(0);
    });

    it('should fail for an empty recipient', async () => {
      const result = await adapter.send({
        type: 'webhook',
        recipient: '',
        subject: 'Test',
        body: 'Test body',
      });

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid webhook URL');
    });

    it('should fail for an email address as recipient', async () => {
      const result = await adapter.send({
        type: 'webhook',
        recipient: 'alice@example.com',
        subject: 'Test',
        body: 'Test body',
      });

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid webhook URL');
      expect(adapter.getSentWebhookCount()).toBe(0);
    });

    it('should trim whitespace from the URL', async () => {
      await adapter.send({
        type: 'webhook',
        recipient: '  https://example.com/hook  ',
        subject: 'Test',
        body: 'Body',
      });

      const webhooks = adapter.getSentWebhooks();
      expect(webhooks).toHaveLength(1);
      expect(webhooks[0]!.url).toBe('https://example.com/hook');
    });

    it('should default priority to normal when not specified', async () => {
      await adapter.send({
        type: 'webhook',
        recipient: 'https://example.com/hook',
        subject: 'Test',
        body: 'Body',
      });

      const webhooks = adapter.getSentWebhooks();
      expect(webhooks[0]!.payload.priority).toBe('normal');
    });

    it('should preserve urgent priority in payload', async () => {
      await adapter.send({
        type: 'webhook',
        recipient: 'https://example.com/hook',
        subject: 'Critical Alert',
        body: 'System down.',
        priority: 'urgent',
      });

      const webhooks = adapter.getSentWebhooks();
      expect(webhooks[0]!.payload.priority).toBe('urgent');
    });

    it('should include metadata in the webhook payload', async () => {
      await adapter.send({
        type: 'webhook',
        recipient: 'https://example.com/hook',
        subject: 'Order Update',
        body: 'Status changed.',
        metadata: { orderId: 'ORD-42', previousStatus: 'pending', newStatus: 'confirmed' },
      });

      const webhooks = adapter.getSentWebhooks();
      expect(webhooks[0]!.payload.metadata).toEqual({
        orderId: 'ORD-42',
        previousStatus: 'pending',
        newStatus: 'confirmed',
      });
    });

    it('should generate sequential message IDs', async () => {
      await adapter.send({
        type: 'webhook',
        recipient: 'https://example.com/hook',
        subject: 'First',
        body: '1',
      });
      await adapter.send({
        type: 'webhook',
        recipient: 'https://example.com/hook',
        subject: 'Second',
        body: '2',
      });
      await adapter.send({
        type: 'webhook',
        recipient: 'https://example.com/hook',
        subject: 'Third',
        body: '3',
      });

      const webhooks = adapter.getSentWebhooks();
      expect(webhooks[0]!.messageId).toBe('webhook-0001');
      expect(webhooks[1]!.messageId).toBe('webhook-0002');
      expect(webhooks[2]!.messageId).toBe('webhook-0003');
    });

    it('should never throw — return failure result on unexpected errors', async () => {
      const result = await adapter.send({
        type: 'webhook',
        recipient: 'https://example.com/hook',
        subject: 'Test',
        body: 'Body',
      });

      // The call should not throw
      expect(result).toBeDefined();
      expect(typeof result.success).toBe('boolean');
      expect(result.timestamp).toBeInstanceOf(Date);
    });
  });

  // ---------------------------------------------------------------------------
  // Test helper methods
  // ---------------------------------------------------------------------------
  describe('getSentWebhooks', () => {
    it('should return an empty array initially', () => {
      expect(adapter.getSentWebhooks()).toEqual([]);
    });

    it('should return a copy, not the internal array', async () => {
      await adapter.send({
        type: 'webhook',
        recipient: 'https://example.com/hook',
        subject: 'Test',
        body: 'Body',
      });

      const webhooks1 = adapter.getSentWebhooks();
      const webhooks2 = adapter.getSentWebhooks();
      expect(webhooks1).not.toBe(webhooks2);
      expect(webhooks1).toEqual(webhooks2);
    });
  });

  describe('getSentWebhooksTo', () => {
    it('should filter webhooks by URL', async () => {
      await adapter.send({
        type: 'webhook',
        recipient: 'https://example.com/hook-a',
        subject: 'To A',
        body: 'Hi A.',
      });
      await adapter.send({
        type: 'webhook',
        recipient: 'https://example.com/hook-b',
        subject: 'To B',
        body: 'Hi B.',
      });
      await adapter.send({
        type: 'webhook',
        recipient: 'https://example.com/hook-a',
        subject: 'Another to A',
        body: 'Hi again.',
      });

      expect(adapter.getSentWebhooksTo('https://example.com/hook-a')).toHaveLength(2);
      expect(adapter.getSentWebhooksTo('https://example.com/hook-b')).toHaveLength(1);
      expect(adapter.getSentWebhooksTo('https://example.com/hook-c')).toHaveLength(0);
    });
  });

  describe('getSentWebhookCount', () => {
    it('should return 0 initially', () => {
      expect(adapter.getSentWebhookCount()).toBe(0);
    });

    it('should count sent webhooks correctly', async () => {
      await adapter.send({
        type: 'webhook',
        recipient: 'https://example.com/hook-a',
        subject: 'One',
        body: '1',
      });
      await adapter.send({
        type: 'webhook',
        recipient: 'https://example.com/hook-b',
        subject: 'Two',
        body: '2',
      });

      expect(adapter.getSentWebhookCount()).toBe(2);
    });

    it('should not count failed sends', async () => {
      await adapter.send({
        type: 'webhook',
        recipient: 'invalid-url',
        subject: 'Fail',
        body: 'Fail',
      });

      expect(adapter.getSentWebhookCount()).toBe(0);
    });
  });

  describe('clearSentWebhooks', () => {
    it('should clear all sent webhooks', async () => {
      await adapter.send({
        type: 'webhook',
        recipient: 'https://example.com/hook',
        subject: 'Test',
        body: 'Body',
      });

      expect(adapter.getSentWebhookCount()).toBe(1);

      adapter.clearSentWebhooks();

      expect(adapter.getSentWebhookCount()).toBe(0);
      expect(adapter.getSentWebhooks()).toEqual([]);
    });
  });

  // ---------------------------------------------------------------------------
  // Integration: full pipeline
  // ---------------------------------------------------------------------------
  describe('full send pipeline', () => {
    it('should compose a complete webhook delivery for an order notification', async () => {
      const result = await adapter.send({
        type: 'webhook',
        recipient: 'https://hooks.myapp.com/orders',
        subject: 'Order Confirmation: ORD-42',
        body: 'Your order has been placed. Items: Widget x2, Gadget x1. Total: $45.00',
        priority: 'normal',
        metadata: { orderId: 'ORD-42', userId: 'user-1' },
      });

      expect(result.success).toBe(true);

      const webhook = adapter.getSentWebhooks()[0]!;
      expect(webhook.url).toBe('https://hooks.myapp.com/orders');
      expect(webhook.statusCode).toBe(200);
      expect(webhook.payload.event).toBe('notification');
      expect(webhook.payload.subject).toBe('Order Confirmation: ORD-42');
      expect(webhook.payload.body).toContain('Widget x2, Gadget x1');
      expect(webhook.payload.body).toContain('$45.00');
      expect(webhook.payload.priority).toBe('normal');
      expect(webhook.payload.metadata).toEqual({ orderId: 'ORD-42', userId: 'user-1' });
      expect(webhook.payload.timestamp).toBeDefined();
    });

    it('should compose a high-priority webhook delivery', async () => {
      const result = await adapter.send({
        type: 'webhook',
        recipient: 'https://hooks.myapp.com/alerts',
        subject: 'Order Update: ORD-99',
        body: 'Your order status has changed from confirmed to shipped.',
        priority: 'high',
      });

      expect(result.success).toBe(true);

      const webhook = adapter.getSentWebhooks()[0]!;
      expect(webhook.payload.priority).toBe('high');
